// isolatedModules forbids:
export type { Foo };     // type-only re-export — ambiguous to single-file tools
const enum Direction { Up, Down }  // requires cross-file const evaluation

// Fix:
export { type Foo };     // OK: inline 'type' keyword
enum Direction { Up, Down }  // use regular enum instead

{
  "include": ["src/**/*.ts"],   // not "." or "./**/*" which picks up node_modules
  "exclude": ["node_modules", "dist", "**/*.spec.ts"]
}

{
  "compilerOptions": {
    "strict": true,
    /* Can then selectively loosen one flag: */
    "strictPropertyInitialization": false
  }
}
